import java.sql.*;

public class SecureSQLQuery {

    public static void main(String[] args) {
        try {
            // Simulating user input (this should be properly sanitized in a real application)
            String userInput = "'; DROP TABLE users; --";

            // Establishing a connection to the database (assumed for demonstration purposes)
